package com.hedera.cryptography.utils.test.fixtures.rng;

import edu.umd.cs.findbugs.annotations.NonNull;
import java.util.Random;

/**
 * A random number generator that is always seeded with a fixed seed.
 */
public class SeededRandom extends Random {
    private final long seed;

    /**
     * Creates a new seeded random number generator.
     */
    public SeededRandom() {
        this(new Random().nextLong());
    }

    /**
     * Creates a new seeded random number generator with the given seed.
     *
     * @param seed the seed
     */
    public SeededRandom(long seed) {
        super(seed);
        this.seed = seed;
        System.out.println("Random with seed: " + seed);
    }

    /**
     * Throws an {@link UnsupportedOperationException} as the seed of a {@link SeededRandom} instance cannot be changed.
     */
    @Override
    public synchronized void setSeed(long seed) {
        throw new UnsupportedOperationException("Cannot change the seed of a SeededRandom instance");
    }

    /**
     * Returns the seed of this random number generator.
     *
     * @return the seed
     */
    public long getSeed() {
        return seed;
    }

    /**
     * Generates random bytes.
     *
     * @param size the size of the byte array to generate
     *
     * @return the generated byte array
     */
    public @NonNull byte[] randomBytes(final int size) {
        final byte[] bytes = new byte[size];
        super.nextBytes(bytes);
        return bytes;
    }
}
